    const [activeCategory, setActiveCategory] = useState<'churches' | 'unidentified' | 'expenses'>('unidentified');
    const [selectedReportId, setSelectedReportId] = useState<string | null>(null);
    const [sortConfig, setSortConfig] = useState<{ key: string, direction: 'asc' | 'desc' } | null>(null);
    const [searchTerm, setSearchTerm] = useState('');
    const [selectedIds, setSelectedIds] = useState<string[]>([]);

    useEffect(() => {
        if (!reportPreviewData) return;

        if (activeCategory === 'churches') {
            const churchIds = Object.keys(reportPreviewData.income).filter(k => k !== 'unidentified').sort();
            if (churchIds.length > 0) {
                if (!selectedReportId || !churchIds.includes(selectedReportId)) {
                    setSelectedReportId(churchIds[0]);
                }
            } else setSelectedReportId(null);
        } else if (activeCategory === 'unidentified') {
            setSelectedReportId('unidentified');
        } else if (activeCategory === 'expenses') {
            setSelectedReportId('all_expenses_group');
        }
        setSelectedIds([]);
    }, [activeCategory, reportPreviewData]);

    const churchList = useMemo(() => {
        if (!reportPreviewData?.income) return [];
        return Object.entries(reportPreviewData.income)
            .filter(([id]) => id !== 'unidentified')
            .map(([id, results]) => ({
                id,
                name: (results as MatchResult[])[0]?.church?.name || 'Igreja Desconhecida',
                count: (results as MatchResult[]).length,
                total: (results as MatchResult[]).reduce((sum, r) => sum + r.transaction.amount, 0)
            })).sort((a, b) => a.name.localeCompare(b.name));
    }, [reportPreviewData]);

    const counts = useMemo(() => ({
        churches: churchList.length,
        pending: reportPreviewData?.income['unidentified']?.length || 0,
        expenses: reportPreviewData?.expenses['all_expenses_group']?.length || 0
    }), [churchList, reportPreviewData]);

    const activeData = useMemo(() => {
        if (!reportPreviewData) return [];
        let data: MatchResult[] = activeCategory === 'expenses' ? reportPreviewData.expenses['all_expenses_group'] || [] :
                                 selectedReportId ? reportPreviewData.income[selectedReportId] || [] : [];

        if (searchTerm) {
            const lower = searchTerm.toLowerCase();
            data = data.filter(r => (r.transaction.description || '').toLowerCase().includes(lower) || (r.contributor?.name || '').toLowerCase().includes(lower));
        }
        return data;
    }, [reportPreviewData, selectedReportId, activeCategory, searchTerm]);

    const activeSummary = useMemo(() => {
        const total = activeData.reduce((sum, r) => sum + (r.status === 'PENDENTE' ? (r.contributorAmount || r.contributor?.amount || 0) : r.transaction.amount), 0);
        const autoTxs = activeData.filter(r => r.status === 'IDENTIFICADO' && r.matchMethod !== 'MANUAL');
        const manualTxs = activeData.filter(r => r.status === 'IDENTIFICADO' && r.matchMethod === 'MANUAL');
        const pendingTxs = activeData.filter(r => r.status === 'PENDENTE' || r.status === 'NÃO IDENTIFICADO');
        return {
            count: activeData.length, total,
            pending: pendingTxs.length, pendingValue: pendingTxs.reduce((s, r) => s + (r.status === 'PENDENTE' ? (r.contributorAmount || r.contributor?.amount || 0) : r.transaction.amount), 0),
            auto: autoTxs.length, autoValue: autoTxs.reduce((s, r) => s + r.transaction.amount, 0),
            manual: manualTxs.length, manualValue: manualTxs.reduce((s, r) => s + r.transaction.amount, 0)
        };
    }, [activeData]);

    const handleSort = (key: string) => setSortConfig(curr => ({ key, direction: curr?.key === key && curr.direction === 'asc' ? 'desc' : 'asc' }));

    const sortedData = useMemo(() => {
        if (!sortConfig) return activeData;
        return [...activeData].sort((a, b) => {
            const parts = sortConfig.key.split('.');
            const getVal = (obj: any) => parts.reduce((o, k) => o?.[k], obj) || '';
            const valA = getVal(a), valB = getVal(b);
            if (valA < valB) return sortConfig.direction === 'asc' ? -1 : 1;
            if (valA > valB) return sortConfig.direction === 'asc' ? 1 : -1;
            return 0;
        });
    }, [activeData, sortConfig]);

    const getReportTitle = () => activeCategory === 'churches' ? (churchList.find(c => c.id === selectedReportId)?.name || 'Igreja') : activeCategory === 'unidentified' ? 'Pendentes' : 'Saídas';

    const handleToggleSelect = (id: string) => {
        setSelectedIds(prev => prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]);
    };

    const handleBulkIdentify = () => {
        const txsToIdentify = matchResults
            .filter(r => selectedIds.includes(r.transaction.id))
            .map(r => r.transaction);

        if (txsToIdentify.length > 0) {
            setManualIdentificationTx(null);
            setBulkIdentificationTxs(txsToIdentify);
            setSelectedIds([]); 
        }
    };

    const handleActionClick = (row: MatchResult) => {
        // Se estivermos na categoria de Pendentes ou o item não estiver identificado, abrimos a escolha de igreja de destino
        // Usamos status explicitamente para garantir que registros "fantasmas" (PENDENTE) também abram o seletor
        if (activeCategory === 'unidentified' || row.status === ReconciliationStatus.UNIDENTIFIED || row.status === ReconciliationStatus.PENDING) {
            // Limpa o estado de lote para evitar conflitos
            setBulkIdentificationTxs(null);
            // Abre o modal de identificação manual para a transação específica
            openManualIdentify(row.transaction.id);
        } else {
            // Se já estiver em um relatório de igreja, abrimos o editor inteligente completo
            openSmartEdit(row);
        }
    };

    const CategoryPill = ({ id, label, count, icon: Icon }: any) => {
        const isActive = activeCategory === id;
        const colorClasses: Record<string, string> = {
            churches: "from-blue-600 to-indigo-600 shadow-blue-500/30",
            unidentified: "from-amber-500 to-orange-500 shadow-orange-500/30",
            expenses: "from-rose-500 to-red-600 shadow-red-500/30"
        };
        return (
            <button onClick={() => setActiveCategory(id)} className={`relative flex items-center gap-2 px-3 py-1.5 rounded-full transition-all text-[10px] font-bold uppercase ${isActive ? `bg-gradient-to-r ${colorClasses[id]} text-white scale-105 z-10` : 'bg-white dark:bg-slate-800 text-slate-500 border border-slate-200 dark:border-slate-700'}`}>
                <Icon className={`w-3.5 h-3.5 ${isActive ? 'text-white' : ''}`} />
                <span>{label}</span>
                <span className={`px-1.5 py-0.5 rounded-md text-[9px] ${isActive ? 'bg-white/20' : 'bg-slate-100 dark:bg-slate-900'}`}>{count}</span>
            </button>
        );
    };

    if (!reportPreviewData) return (
        <div className="flex-1 flex items-center justify-center">
            <EmptyState icon={<ChartBarIcon className="w-12 h-12 text-brand-blue" />} title={t('empty.reports.title')} message={t('empty.reports.message')} action={{ text: t('empty.dashboard.saved.action'), onClick: () => setActiveView('upload') }} />
        </div>
    );

    return (
        <div className="flex flex-col h-full gap-2 pb-2 px-1 animate-fade-in relative">
            <div className="flex flex-col xl:flex-row xl:items-center justify-between gap-2 shrink-0">
                <div className="flex items-center gap-4">
                    <h2 className="text-lg font-black dark:text-white leading-none">{t('reports.title')}</h2>
                    <div className="flex items-center gap-2 bg-slate-100 dark:bg-slate-900/50 p-0.5 rounded-full border border-slate-200 dark:border-slate-800">
                        <CategoryPill id="churches" label="Igrejas" count={counts.churches} icon={BuildingOfficeIcon} />
                        <CategoryPill id="unidentified" label="Pendentes" count={counts.pending} icon={ExclamationTriangleIcon} />
                        <CategoryPill id="expenses" label="Saídas" count={counts.expenses} icon={BanknotesIcon} />
                    </div>
                </div>
                <div className="flex items-center gap-2 ml-auto">
                    {selectedIds.length > 0 && activeCategory === 'unidentified' && (
                        <button 
                            onClick={handleBulkIdentify}
                            className="flex items-center gap-2 px-6 py-2 bg-gradient-to-r from-blue-600 to-indigo-600 text-white rounded-full text-[10px] font-black uppercase tracking-widest shadow-lg shadow-blue-500/30 animate-scale-in"
                        >
                            <CheckBadgeIcon className="w-4 h-4" />
                            <span>Identificar Selecionados ({selectedIds.length})</span>
                        </button>
                    )}

                    <div className="flex items-center gap-1 bg-slate-100 dark:bg-slate-800 rounded-full p-1 border border-slate-200 dark:border-slate-700">
                        <button onClick={() => setActiveView('upload')} className="p-1.5 text-slate-500 hover:text-indigo-600" title="Gerenciar Arquivos"><ArrowPathIcon className="w-4 h-4" /></button>
                        <button onClick={() => ExportService.downloadCsv(sortedData, `relatorio_${getReportTitle().toLowerCase()}.csv`)} className="p-1.5 text-slate-400 hover:text-brand-blue" title="Baixar CSV"><DocumentArrowDownIcon className="w-4 h-4" /></button>
                        <button onClick={() => ExportService.printHtml(sortedData, getReportTitle(), activeSummary, language)} className="p-1.5 text-slate-400 hover:text-brand-blue" title="Imprimir"><PrinterIcon className="w-4 h-4" /></button>
                    </div>
                    {activeReportId && (
                        <button onClick={saveCurrentReportChanges} className="flex items-center gap-2 px-4 py-2 bg-gradient-to-r from-amber-500 to-orange-500 text-white rounded-full text-[10px] font-bold uppercase shadow-lg"><FloppyDiskIcon className="w-3.5 h-3.5" /><span>Salvar Alt.</span></button>
                    )}
                    <button onClick={() => openSaveReportModal({ type: 'global', results: matchResults, groupName: 'Geral' })} className="flex items-center gap-2 px-6 py-2 bg-gradient-to-r from-emerald-600 to-teal-600 text-white rounded-full text-[10px] font-bold uppercase shadow-lg"><DocumentDuplicateIcon className="w-3.5 h-3.5" /><span>{t('reports.saveReport')}</span></button>
                </div>
            </div>

            {activeCategory === 'churches' && (
                <div className="flex gap-2 overflow-x-auto custom-scrollbar pb-2 px-1">
                    {churchList.map(item => (
                        <button key={item.id} onClick={() => setSelectedReportId(item.id)} className={`flex-shrink-0 flex items-center gap-2 px-3 py-1 rounded-full border transition-all text-xs ${selectedReportId === item.id ? 'bg-blue-50 border-blue-200 text-blue-700' : 'bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700 text-slate-600'}`}>
                            <span className="font-bold truncate max-w-[150px]">{item.name}</span>
                            <span className="px-1.5 rounded text-[10px] font-bold bg-slate-100">{item.count}</span>
                        </button>
                    ))}
                </div>
            )}

            <div className="flex-1 bg-white dark:bg-slate-800 rounded-2xl border border-slate-100 dark:border-slate-700 shadow-card overflow-hidden flex flex-col">
                <div className="px-4 py-2 bg-slate-50/80 dark:bg-slate-900/50 border-b flex flex-col md:flex-row md:items-center justify-between gap-2 shrink-0 backdrop-blur-sm">
                    <div className="flex items-center gap-3">
                        <div className="flex flex-col leading-tight">
                            <h3 className="text-xs font-black dark:text-white uppercase">{getReportTitle()}</h3>
                            <div className="flex items-center gap-2 text-[10px] font-bold text-slate-500">
                                <span>Total: {activeSummary.count}</span>
                                <span className="w-px h-2 bg-slate-300"></span>
                                <span className={activeCategory === 'expenses' ? 'text-red-600' : 'text-emerald-600'}>{formatCurrency(activeSummary.total, language)}</span>
                            </div>
                        </div>
                    </div>
                    <div className="flex items-center gap-2">
                        <ReportSummaryCards summary={activeSummary} language={language} activeCategory={activeCategory} />
                        <div className="relative group ml-2">
                            <MagnifyingGlassIcon className="w-3.5 h-3.5 text-slate-400 absolute left-2 top-1/2 -translate-y-1/2" />
                            <input type="text" placeholder="Filtrar..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} className="pl-7 pr-2 py-1 bg-white dark:bg-slate-900 border rounded-lg text-[10px] focus:ring-1 focus:ring-brand-blue outline-none w-24 focus:w-40 transition-all" />
                        </div>
                    </div>
                </div>
                <div className="flex-1 relative">
                    <div className="absolute inset-0">
                        <EditableReportTable 
                            data={sortedData} 
                            onRowChange={updateReportData} 
                            reportType={activeCategory === 'expenses' ? 'expenses' : 'income'} 
                            sortConfig={sortConfig} 
                            onSort={handleSort} 
                            loadingAiId={loadingAiId} 
                            onEdit={handleActionClick} 
                            selectedIds={selectedIds}
                            onToggleSelect={handleToggleSelect}
                            onSelectAll={activeCategory === 'unidentified' ? setSelectedIds : undefined}
                        />
                    </div>
                </div>
            </div>
        </div>
    );
};

import React, { useState, useContext, memo, useCallback, useMemo } from 'react';
import { MatchResult, ReconciliationStatus } from '../../types';
import { AppContext } from '../../contexts/AppContext';
import { useTranslation } from '../../contexts/I18nContext';
import { formatCurrency, formatDate } from '../../utils/formatters';
import { 
    PencilIcon, 
    ChevronUpIcon, 
    ChevronDownIcon, 
    TrashIcon, 
    ExclamationTriangleIcon, 
    ChevronLeftIcon, 
    ChevronRightIcon, 
    UserIcon,
    UserPlusIcon,
    SparklesIcon,
    BrainIcon,
    BanknotesIcon,
    ArrowUturnLeftIcon,
    CheckCircleIcon
} from '../Icons';
import { formatIncomeDescription } from '../../services/processingService';

type SortDirection = 'asc' | 'desc';
interface SortConfig {
    key: string;
    direction: SortDirection;
}

interface EditableReportTableProps {
    data: MatchResult[];
    onRowChange: (updatedRow: MatchResult) => void;
    reportType: 'income' | 'expenses';
    sortConfig: SortConfig | null;
    onSort: (key: string) => void;
    loadingAiId: string | null; 
    onEdit?: (row: MatchResult) => void;
    // Multi-select props
    selectedIds?: string[];
    onToggleSelect?: (id: string) => void;
    onSelectAll?: (ids: string[]) => void;
}

const ITEMS_PER_PAGE = 50;

const SortableHeader: React.FC<{
    sortKey: string;
    title: string;
    sortConfig: SortConfig | null;
    onSort: (key: string) => void;
    className?: string;
}> = memo(({ sortKey, title, sortConfig, onSort, className = '' }) => {
    const isSorted = sortConfig?.key === sortKey;
    return (
        <th scope="col" className={`px-4 py-3 text-left text-[10px] font-bold text-slate-700 dark:text-slate-200 uppercase tracking-wider ${className}`}>
            <button onClick={() => onSort(sortKey)} className="flex items-center gap-1.5 group hover:text-black dark:hover:text-white transition-colors focus:outline-none w-full justify-center">
                <span>{title}</span>
                <span className={`transition-all duration-200 ${isSorted ? 'opacity-100 text-brand-blue dark:text-blue-400' : 'opacity-0 group-hover:opacity-50'}`}>
                    {sortConfig?.direction === 'asc' ? <ChevronUpIcon className="w-3 h-3" /> : <ChevronDownIcon className="w-3 h-3" />}
                </span>
            </button>
        </th>
    );
});

const MatchMethodIcon: React.FC<{ method: MatchResult['matchMethod'] }> = ({ method }) => {
    if (!method || method === 'AUTOMATIC') return null;

    const iconMap = {
        LEARNED: { Icon: BrainIcon, color: 'text-purple-500 bg-purple-50 dark:bg-purple-900/30 dark:text-purple-400' },
        AI: { Icon: SparklesIcon, color: 'text-teal-500 bg-teal-50 dark:bg-teal-900/30 dark:text-teal-400' },
        MANUAL: { Icon: UserPlusIcon, color: 'text-blue-500 bg-blue-50 dark:bg-blue-900/30 dark:text-blue-400' },
        TEMPLATE: { Icon: SparklesIcon, color: 'text-indigo-500 bg-indigo-50 dark:bg-indigo-900/30 dark:text-indigo-400' }
    };

    const config = iconMap[method];
    if (!config) return null;

    return (
        <span className={`ml-1.5 p-1 rounded-md ${config.color} inline-flex items-center justify-center`} title={method}>
            <config.Icon className="w-3 h-3" />
        </span>
    );
}

const IncomeRow = memo(({ 
    result, 
    language, 
    onEdit, 
    onDelete, 
    onUndo,
    openDivergence, 
    ignoreKeywords,
    isSelected,
    onToggleSelect
}: any) => {
    const row = result as MatchResult;
    const isGhost = row.status === ReconciliationStatus.PENDING;
    const isIdentified = row.status === ReconciliationStatus.IDENTIFIED;
    const isUnidentified = row.status === ReconciliationStatus.UNIDENTIFIED;

    const bankAmount = row.transaction.amount;
    const listAmount = row.contributorAmount || row.contributor?.amount || 0;

    const bankDate = row.transaction.date;
    const listDate = row.contributor?.date || bankDate;
    const hasDateDivergence = isIdentified && bankDate !== listDate;
    const hasValueDivergence = isIdentified && Math.abs(bankAmount - listAmount) >= 0.01;

    const txDescFormatted = formatIncomeDescription(row.transaction.description, ignoreKeywords);
    const displayName = row.contributor?.name || row.contributor?.cleanedName || txDescFormatted;

    const contribType = row.contributor?.contributionType;
    const bankType = row.transaction.contributionType;

    const getStatusBadge = () => {
        if (!isIdentified && !isGhost) {
            return (
                <span className="inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-[9px] font-bold bg-amber-50 text-amber-700 border border-amber-100 dark:bg-amber-900/30 dark:text-amber-400 dark:border-amber-800 uppercase tracking-wide whitespace-nowrap">
                    Pendente
                </span>
            );
        }

        if (isGhost) {
            return (
                <span className="inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-[9px] font-bold bg-slate-100 text-slate-500 border border-slate-200 dark:bg-slate-700 dark:text-slate-300 dark:border-slate-600 uppercase tracking-wide whitespace-nowrap">
                    Não Localizado
                </span>
            );
        }

        let bgClass = 'bg-emerald-50 border-emerald-100 text-emerald-700 dark:bg-emerald-900/30 dark:border-emerald-800 dark:text-emerald-400';
        let label = 'Auto';

        if (row.matchMethod === 'MANUAL') {
            bgClass = 'bg-blue-50 border-blue-100 text-blue-700 dark:bg-blue-900/30 dark:border-blue-800 dark:text-blue-400';
            label = 'Manual';
        } else if (row.matchMethod === 'AI') {
            bgClass = 'bg-teal-50 border-teal-100 text-teal-700 dark:bg-teal-900/30 dark:border-teal-800 dark:text-teal-400';
            label = 'IA';
        } else if (row.matchMethod === 'LEARNED') {
             bgClass = 'bg-purple-50 border-purple-100 text-purple-700 dark:bg-purple-900/30 dark:border-purple-800 dark:text-purple-400';
             label = 'Aprendido';
        }

        return (
            <span className={`inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-[9px] font-bold border uppercase tracking-wide whitespace-nowrap ${bgClass}`}>
                {label}
            </span>
        );
    };

    return (
        <tr className={`
            group 
            transition-colors 
            border-b border-slate-200 dark:border-slate-700 
            ${isSelected ? 'bg-blue-50 dark:bg-blue-900/40' : 'hover:bg-slate-50 dark:hover:bg-blue-900/10'}
            ${isGhost 
                ? 'bg-amber-50/50 dark:bg-amber-900/10' 
                : 'odd:bg-white even:bg-slate-50 dark:odd:bg-slate-800 dark:even:bg-slate-800/40'
            }
        `}>
            <td className="px-4 py-2.5 w-10 text-center">
                {(isUnidentified || isGhost) && onToggleSelect && (
                    <div 
                        onClick={(e) => { e.stopPropagation(); onToggleSelect(row.transaction.id); }}
                        className={`w-4 h-4 rounded border flex items-center justify-center cursor-pointer transition-all mx-auto ${isSelected ? 'bg-brand-blue border-brand-blue' : 'bg-white border-slate-300 hover:border-brand-blue'}`}
                    >
                        {isSelected && <CheckCircleIcon className="w-3 h-3 text-white" />}
                    </div>
                )}
            </td>

            <td className="px-4 py-2.5 font-mono text-[11px]">
                {hasDateDivergence ? (
                    <div className="flex flex-col">
                        <div className="flex items-center gap-1" title="Data no Extrato">
                            <BanknotesIcon className="w-2.5 h-2.5 text-slate-400" />
                            <span className="text-slate-700 dark:text-slate-200 font-bold">{formatDate(bankDate)}</span>
                        </div>
                        <div className="flex items-center gap-1" title="Data na Lista">
                            <UserIcon className="w-2.5 h-2.5 text-indigo-400" />
                            <span className="text-indigo-600 dark:text-indigo-400 font-bold">{formatDate(listDate)}</span>
                        </div>
                    </div>
                ) : (
                    <span className="text-slate-500 dark:text-slate-400">
                        {formatDate(isGhost ? listDate : bankDate)}
                    </span>
                )}
            </td>

            <td className="px-4 py-2.5">
                <div className="flex flex-col gap-1">
                    <div className="flex items-center gap-2">
                        {(row.contributor || isGhost) ? (
                            <UserIcon className="w-3.5 h-3.5 text-indigo-500 shrink-0" title="Origem: Lista de Contribuintes" />
                        ) : (
                            <BanknotesIcon className="w-3.5 h-3.5 text-slate-400 shrink-0" title="Origem: Extrato Bancário" />
                        )}

                        <span className={`text-xs font-bold leading-tight truncate max-w-[250px] ${isGhost ? 'text-slate-500 dark:text-slate-400' : 'text-slate-900 dark:text-white'}`} title={displayName}>
                            {displayName}
                        </span>
                    </div>

                    {isIdentified && displayName !== txDescFormatted && (
                        <div className="flex items-center gap-2 opacity-80">
                            <BanknotesIcon className="w-3.5 h-3.5 text-slate-400 shrink-0" title="Origem: Extrato Bancário" />
                            <span className="text-[10px] text-slate-500 dark:text-slate-400 font-medium truncate max-w-[250px]">
                                {txDescFormatted}
                            </span>
                        </div>
                    )}

                    {isGhost && (
                        <span className="text-[9px] text-red-400 pl-5 font-medium italic">
                            Não identificado no banco
                        </span>
                    )}
                </div>
            </td>

            <td className="px-4 py-2.5 text-center">
                <div className="flex items-center justify-center">
                    {getStatusBadge()}
                    {isIdentified && <MatchMethodIcon method={row.matchMethod} />}
                </div>
            </td>
            <td className="px-4 py-2.5 text-center">
                <span className={`text-[10px] font-bold ${row.similarity && row.similarity >= 90 ? 'text-emerald-600 dark:text-emerald-400' : row.similarity && row.similarity >= 70 ? 'text-blue-600 dark:text-blue-400' : 'text-slate-400'}`}>
                    {row.similarity ? `${row.similarity.toFixed(0)}%` : '-'}
                </span>
            </td>

            <td className="px-4 py-2.5">
                <div className="flex flex-col gap-1.5 items-start">
                    {(row.contributor || isGhost) && (
                        <div className="flex items-center gap-1.5" title="Tipo na Lista">
                            <UserIcon className="w-3 h-3 text-indigo-400 shrink-0" />
                            <span className="text-[9px] font-bold text-indigo-700 bg-indigo-50 border border-indigo-100 dark:bg-indigo-900/30 dark:text-indigo-300 dark:border-indigo-800 px-1.5 py-0.5 rounded uppercase tracking-wide leading-none">
                                {contribType || '---'}
                            </span>
                        </div>
                    )}

                    {!isGhost && (
                        <div className="flex items-center gap-1.5 opacity-80" title="Tipo no Extrato">
                            <BanknotesIcon className="w-3 h-3 text-slate-400 shrink-0" />
                            <span className="text-[9px] font-medium text-slate-600 bg-slate-100 border border-slate-200 dark:bg-slate-700/50 dark:text-slate-400 dark:border-slate-700 px-1.5 py-0.5 rounded uppercase tracking-wide leading-none">
                                {bankType || '---'}
                            </span>
                        </div>
                    )}
                </div>
            </td>

            <td className="px-4 py-2.5 text-right whitespace-nowrap">
                {isGhost ? (
                    <div className="flex flex-col items-end">
                        <span className="font-mono text-[10px] text-slate-400 dark:text-slate-500 line-through decoration-slate-300">
                            0,00
                        </span>
                        <span className="text-[9px] text-slate-400 dark:text-slate-500 font-medium">
                            (Exp: {formatCurrency(listAmount, language)})
                        </span>
                    </div>
                ) : hasValueDivergence ? (
                    <div className="flex flex-col items-end gap-0.5">
                        <div className="flex items-center gap-1.5" title="Valor no Extrato">
                            <span className="text-[8px] font-bold text-slate-400 uppercase">Ext</span>
                            <span className="font-mono text-xs font-bold text-slate-900 dark:text-white tabular-nums">
                                {formatCurrency(bankAmount, language)}
                            </span>
                        </div>
                        <div className="flex items-center gap-1.5" title="Valor na Lista">
                            <span className="text-[8px] font-bold text-indigo-400 uppercase">Lis</span>
                            <span className="font-mono text-[10px] font-medium text-indigo-600 dark:text-indigo-400 tabular-nums">
                                {formatCurrency(listAmount, language)}
                            </span>
                        </div>
                    </div>
                ) : (
                    <span className={`font-mono text-xs font-bold tabular-nums tracking-tight ${bankAmount < 0 ? 'text-red-600 dark:text-red-400 font-black' : 'text-slate-900 dark:text-white'}`}>
                        {formatCurrency(bankAmount, language)}
                    </span>
                )}
            </td>
            <td className="px-4 py-2.5 text-center">
                <div className="flex gap-1 justify-center transition-opacity">
                    {!isIdentified && !isGhost ? (
                        <div className="flex items-center justify-center gap-1">
                            <button 
                                onClick={() => onEdit && onEdit(row)} 
                                className={`p-1.5 rounded-lg text-white transition-all shadow-md hover:-translate-y-0.5 ${
                                    row.suggestion 
                                    ? 'bg-gradient-to-r from-purple-50 to-pink-50 hover:from-purple-400 hover:to-pink-400 ring-1 ring-purple-300 dark:ring-purple-700' 
                                    : 'bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-500 hover:to-indigo-500'
                                }`}
                                title={row.suggestion ? "Identificar (Sugestão IA Disponível)" : "Identificar (IA + Manual)"}
                            >
                                {row.suggestion ? <SparklesIcon className="w-3.5 h-3.5 animate-pulse" /> : <UserPlusIcon className="w-3.5 h-3.5" />}
                            </button>
                            <button onClick={() => onDelete(row)} className="p-1.5 rounded-lg text-rose-600 bg-rose-50 hover:bg-rose-100 dark:bg-rose-900/30 dark:text-rose-300 dark:hover:bg-rose-900/50 transition-colors shadow-sm opacity-0 group-hover:opacity-100" title="Excluir">
                                <TrashIcon className="w-3.5 h-3.5" />
                            </button>
                        </div>
                    ) : (
                        <div className="opacity-0 group-hover:opacity-100 transition-opacity flex gap-1">
                            <button onClick={() => onEdit && onEdit(row)} className="p-1.5 rounded-lg text-brand-blue bg-blue-50 hover:bg-blue-100 dark:bg-blue-900/30 dark:text-blue-300 dark:hover:bg-blue-900/50 transition-colors shadow-sm" title="Editar / Corrigir">
                                <PencilIcon className="w-3.5 h-3.5" />
                            </button>

                            {isIdentified && (
                                <button onClick={() => onUndo(row.transaction.id)} className="p-1.5 rounded-lg text-amber-600 bg-amber-50 hover:bg-amber-100 dark:bg-amber-900/30 dark:text-amber-300 dark:hover:bg-amber-900/50 transition-colors shadow-sm" title="Desfazer Identificação">
                                    <ArrowUturnLeftIcon className="w-3.5 h-3.5" />
                                </button>
                            )}

                            {row.divergence && <button onClick={() => openDivergence(row)} className="p-1.5 rounded-lg text-yellow-600 bg-yellow-50 hover:bg-yellow-100 dark:bg-yellow-900/30 dark:text-yellow-300 dark:hover:bg-yellow-900/50 transition-colors shadow-sm" title="Confirmar Divergência"><ExclamationTriangleIcon className="w-3.5 h-3.5" /></button>}

                            <button onClick={() => onDelete(row)} className="p-1.5 rounded-lg text-rose-600 bg-rose-50 hover:bg-rose-100 dark:bg-rose-900/30 dark:text-rose-300 dark:hover:bg-rose-900/50 transition-colors shadow-sm" title="Excluir">
                                <TrashIcon className="w-3.5 h-3.5" />
                            </button>
                        </div>
                    )}
                </div>
            </td>
        </tr>
    );
});

export const EditableReportTable: React.FC<EditableReportTableProps> = memo(({ 
    data, 
    onRowChange, 
    reportType, 
    sortConfig, 
    onSort, 
    loadingAiId, 
    onEdit,
    selectedIds = [],
    onToggleSelect,
    onSelectAll
}) => {
    const { t, language } = useTranslation();
    const { 
        openDivergenceModal, 
        openDeleteConfirmation,
        openSmartEdit,
        undoIdentification 
    } = useContext(AppContext);

    const handleEdit = useCallback((row: MatchResult) => {
        if (onEdit) {
            onEdit(row);
        } else {
            openSmartEdit(row);
        }
    }, [openSmartEdit, onEdit]);

    const handleDelete = useCallback((row: MatchResult) => {
        openDeleteConfirmation({ type: 'report-row', id: row.transaction.id, name: `Transação ${row.transaction.id}`, meta: { reportType } });
    }, [openDeleteConfirmation, reportType]);

    // Pagination
    const [currentPage, setCurrentPage] = useState(1);
    const totalPages = Math.ceil(data.length / ITEMS_PER_PAGE);
    const paginatedData = useMemo(() => {
        const start = (currentPage - 1) * ITEMS_PER_PAGE;
        return data.slice(start, start + ITEMS_PER_PAGE);
    }, [data, currentPage]);

    // Lógica para checkbox "Selecionar Todos" (da página atual)
    const unidentifiedInPage = useMemo(() => 
        paginatedData.filter(r => r.status === ReconciliationStatus.UNIDENTIFIED).map(r => r.transaction.id),
    [paginatedData]);

    const isAllInPageSelected = unidentifiedInPage.length > 0 && unidentifiedInPage.every(id => selectedIds.includes(id));

    const handleToggleAll = () => {
        if (!onSelectAll) return;
        if (isAllInPageSelected) {
            onSelectAll(selectedIds.filter(id => !unidentifiedInPage.includes(id)));
        } else {
            const newSelection = Array.from(new Set([...selectedIds, ...unidentifiedInPage]));
            onSelectAll(newSelection);
        }
    };

    return (
        <div className="flex flex-col h-full w-full bg-white dark:bg-slate-900">
            <div className="flex-1 w-full overflow-auto custom-scrollbar relative">
                <table className="w-full text-left border-collapse">
                    <thead className="bg-slate-200 dark:bg-slate-950 border-b-2 border-slate-300 dark:border-slate-600 sticky top-0 z-20 shadow-sm">
                        <tr>
                            <th className="px-4 py-3 w-10 text-center">
                                {onSelectAll && (
                                    <div 
                                        onClick={handleToggleAll}
                                        className={`w-4 h-4 rounded border flex items-center justify-center cursor-pointer transition-all mx-auto ${isAllInPageSelected ? 'bg-brand-blue border-brand-blue' : 'bg-white border-slate-300 hover:border-brand-blue'}`}
                                        title="Selecionar todos os pendentes desta página"
                                    >
                                        {isAllInPageSelected && <CheckCircleIcon className="w-3 h-3 text-white" />}
                                    </div>
                                )}
                            </th>
                            <SortableHeader sortKey="transaction.date" title={t('table.date')} sortConfig={sortConfig} onSort={onSort} className="w-[12%]" />
                            <SortableHeader sortKey={reportType === 'income' ? 'contributor.name' : 'transaction.description'} title={reportType === 'income' ? 'Nome / Contribuinte' : 'Descrição'} sortConfig={sortConfig} onSort={onSort} className="w-[35%]" />
                            <SortableHeader sortKey="status" title="Status" sortConfig={sortConfig} onSort={onSort} className="text-center w-[10%]" />
                            <SortableHeader sortKey="similarity" title="Simil." sortConfig={sortConfig} onSort={onSort} className="text-center w-[8%]" />
                            <SortableHeader sortKey="contributionType" title="Tipo" sortConfig={sortConfig} onSort={onSort} className="w-[12%]" />
                            <SortableHeader sortKey="transaction.amount" title={t('table.amount')} sortConfig={sortConfig} onSort={onSort} className="text-right w-[13%]" />
                            <SortableHeader sortKey="hasSuggestion" title={t('table.actions')} sortConfig={sortConfig} onSort={onSort} className="text-center w-[10%]" />
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-200 dark:divide-slate-700">
                        {paginatedData.map(result => (
                            <IncomeRow 
                                key={result.transaction.id}
                                result={result}
                                t={t}
                                language={language}
                                onEdit={handleEdit}
                                onDelete={handleDelete}
                                onUndo={undoIdentification}
                                openDivergence={openDivergenceModal}
                                ignoreKeywords={[]}
                                isSelected={selectedIds.includes(result.transaction.id)}
                                onToggleSelect={onToggleSelect}
                            />
                        ))}
                    </tbody>
                </table>
            </div>
            {totalPages > 1 && (
                <div className="flex-shrink-0 flex justify-between items-center px-4 py-3 bg-white dark:bg-slate-800 border-t border-slate-200 dark:border-slate-700 z-30">
                    <span className="text-[10px] font-bold text-slate-500 dark:text-slate-400">Página {currentPage} de {totalPages}</span>
                    <div className="flex items-center gap-2">
                        <button onClick={() => setCurrentPage(p => Math.max(1, p - 1))} disabled={currentPage === 1} className="p-1.5 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-lg disabled:opacity-30 transition-colors"><ChevronLeftIcon className="w-4 h-4 text-slate-600 dark:text-slate-300" /></button>
                        <button onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))} disabled={currentPage === totalPages} className="p-1.5 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-lg disabled:opacity-30 transition-colors"><ChevronRightIcon className="w-4 h-4 text-slate-600 dark:text-slate-300" /></button>
                    </div>
                </div>
            )}
        </div>
    );
});
